import{_ as a,o as t,c as s,a2 as r}from"./chunks/framework.DSelMM11.js";const h=JSON.parse('{"title":"AOSC - Automatic Online Schema Change","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1781637126000}'),i={name:"index.md"};function n(o,e,c,l,p,d){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="aosc-automatic-online-schema-change" tabindex="-1">AOSC - Automatic Online Schema Change <a class="header-anchor" href="#aosc-automatic-online-schema-change" aria-label="Permalink to &quot;AOSC - Automatic Online Schema Change&quot;">​</a></h1><p class="aosc-home-lede"> AOSC moves an OpenSearch index to a pre-created target index while the source remains live. It backfills existing documents, replays source operation history, then briefly blocks source writes to finish catch-up and swap an alias. </p><div class="aosc-home-actions"><a class="aosc-primary-action" href="./get-started/your-first-migration">Run a first migration</a><a class="aosc-secondary-action" href="./how-it-works">See how it works</a></div><div class="aosc-fact-grid"><section><span>Online path</span><p>Backfill and replay run while the source index continues serving application traffic.</p></section><section><span>Explicit cutover</span><p>Source writes are blocked only for final replay, validation, and alias swap.</p></section><section><span>Operational visibility</span><p>Status APIs expose coordinator phase, shard phase, counters, and errors.</p></section></div><div class="tip custom-block"><p class="custom-block-title">When AOSC fits</p><p>AOSC is for same-cluster index migrations where you need a new target index for mappings, settings, shard layout, or document shape, but the source index must keep receiving traffic during most of the move.</p></div><div class="warning custom-block"><p class="custom-block-title">Cutover is not zero-interruption</p><p>Applications must retry writes rejected during the brief source write block. Successful cutovers have been observed in the 2s-30s range, but your window depends on index size, shard count, write load, and cluster-manager responsiveness.</p></div><div class="vp-card-grid"><a class="vp-card" href="./get-started/your-first-migration"><strong>Run it locally</strong><span>Build the plugin, start a test cluster, keep writes running, and watch cutover.</span></a><a class="vp-card" href="./how-it-works"><strong>Understand the flow</strong><span>Follow source writes, shard workers, catch-up, and alias movement step by step.</span></a><a class="vp-card" href="./reference/rest-api"><strong>Use the API</strong><span>Start, monitor, cancel, list, and clean up migrations from REST endpoints.</span></a></div><h2 id="why-aosc" tabindex="-1">Why AOSC? <a class="header-anchor" href="#why-aosc" aria-label="Permalink to &quot;Why AOSC?&quot;">​</a></h2><p>Many OpenSearch index properties cannot be changed in place. Changing field types, analyzers, routing assumptions, or shard counts usually means creating a new index and copying data.</p><p>AOSC automates the parts that are risky to do by hand:</p><ul><li>Backfill source documents into the target.</li><li>Replay source-shard operation history so writes during backfill are applied to the target.</li><li>Track per-shard progress and expose status through REST APIs.</li><li>Perform alias cutover after a source write block and final catch-up.</li></ul><p>AOSC still requires planning. The target index must be created first, applications must use an alias for cutover, and applications must retry writes rejected during the cutover write block.</p>',12)])])}const m=a(i,[["render",n]]);export{h as __pageData,m as default};
